const keymapBase64 = `data:image/png;base64,`;

function openKeymap() {
  const htmlContent = `
<!DOCTYPE html>
<html>
<head>
  <title>Pixel Art Edition</title>
  <link rel="icon" type="image/png" href="data:image/png;base64,">
</head>
<body style="margin:0;background:#101C52">
  <img src="${keymapBase64}" style="image-rendering:pixelated" alt="keymap">
</body>
</html>`;

  const blob = new Blob([htmlContent], { type: 'text/html' });
  const blobUrl = URL.createObjectURL(blob);
  window.open(blobUrl);
}



